using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient via MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Tool definitions ---
var tools = new ResearchTools();
var aiTools = new List<AITool>
{
    AIFunctionFactory.Create(tools.SearchWeb),
    AIFunctionFactory.Create(tools.SaveNote),
    AIFunctionFactory.Create(tools.GetNotes),
};

// --- Create the agent with Microsoft Agent Framework ---
var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An AI agent that researches topics by searching the web and taking notes.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = aiTools,
        },
    });

// --- Main loop ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       Research Agent (MAF + MEAI)    ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine("Enter a topic to research, or 'quit' to exit.\n");

while (true)
{
    Console.Write("Topic> ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
    {
        break;
    }

    tools.ClearNotes();

    var messages = new List<ChatMessage>
    {
        new(ChatRole.User,
            $"""
            Research the following topic: "{topic}"

            Follow these steps:
            1. Search the web for information about the topic (perform 2-3 searches with different queries).
            2. Save important findings as notes using the note-taking tool.
            3. Review your notes, then provide a comprehensive summary of your research.

            Begin researching now.
            """),
    };

    Console.WriteLine($"\n🔍 Researching: {topic}\n");

    try
    {
        var response = await agent.RunAsync(messages);
        Console.WriteLine("\n📋 Research Summary:");
        Console.WriteLine(new string('─', 50));
        Console.WriteLine(response.Text);
        Console.WriteLine(new string('─', 50));
    }
    catch (Exception ex)
    {
        Console.WriteLine($"\n❌ Error: {ex.Message}");
    }

    Console.WriteLine();
}

Console.WriteLine("Goodbye!");

