/// <summary>
/// Provides web search and note-taking tools for the research agent.
/// </summary>
sealed class ResearchTools
{
    private readonly List<string> _notes = [];
    private readonly HttpClient _httpClient = new();

    [Description("Search the web for information on a query. Returns a list of search result snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query to look up on the web.")] string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        try
        {
            // Use Wikipedia's public API as a free, no-key-required search source.
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={encoded}&srlimit=4&format=json&utf8=1";

            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.Add("User-Agent", "ResearchAgent/1.0 (educational demo)");

            using var response = await _httpClient.SendAsync(request);
            response.EnsureSuccessStatusCode();

            var json = await response.Content.ReadAsStringAsync();
            using var doc = JsonDocument.Parse(json);

            var results = new StringBuilder();
            results.AppendLine($"Search results for: \"{query}\"\n");

            if (doc.RootElement.TryGetProperty("query", out var queryEl)
                && queryEl.TryGetProperty("search", out var searchEl))
            {
                int i = 1;
                foreach (var item in searchEl.EnumerateArray())
                {
                    var title = item.GetProperty("title").GetString();
                    var snippet = item.GetProperty("snippet").GetString()
                        ?.Replace("<span class=\"searchmatch\">", "")
                        .Replace("</span>", "");
                    results.AppendLine($"{i}. **{title}**: {snippet}");
                    i++;
                }
            }

            if (results.Length == 0)
            {
                return "No results found.";
            }

            return results.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Save a research note. Use this to record important findings during research.")]
    public string SaveNote(
        [Description("The note content to save.")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note saved ({_notes.Count} total)");
        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"Research notes ({_notes.Count} total):\n");
        for (int i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"[{i + 1}] {_notes[i]}");
        }

        return sb.ToString();
    }

    public void ClearNotes() => _notes.Clear();
}

